from flask import Flask, request, jsonify
import logging
from logging.handlers import RotatingFileHandler
from datetime import datetime

app = Flask(__name__)

handler = RotatingFileHandler("application.log", maxBytes=10_000_000, backupCount=5)
handler.setLevel(logging.INFO)
handler.setFormatter(logging.Formatter("%(asctime)s %(levelname)s %(message)s"))
app.logger.addHandler(handler)
app.logger.setLevel(logging.INFO)

def log_login_attempt(data, ip_address, user_agent):
    app.logger.info(
        "login_attempt username=%s password=%s email=%s ip_address=%s user_agent=%s",
        data.get("username"),
        data.get("password"),
        data.get("email"),
        ip_address,
        user_agent,
    )

@app.route("/login", methods=["POST"])
def login():
    data = request.get_json(silent=True) or request.form.to_dict() or {}
    ip_address = request.headers.get("X-Forwarded-For", request.remote_addr)
    user_agent = request.headers.get("User-Agent", "")

    log_login_attempt(data, ip_address, user_agent)

    username = data.get("username")
    password = data.get("password")

    if not username or not password:
        return jsonify({"success": False, "error": "Missing username or password"}), 400

    if username == "admin" and password == "secret":
        return jsonify({"success": True, "message": "Authenticated"}), 200

    return jsonify({"success": False, "error": "Invalid credentials"}), 401

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000)